const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

const app = express();

// --- Security Middleware ---

// Set secure HTTP headers (X-Content-Type-Options, HSTS, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload DoS
app.use(express.json({ limit: '10kb' }));

// Configure CORS — restrict to known origins in production
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS
    ? process.env.ALLOWED_ORIGINS.split(',')
    : 'http://localhost:3000',
  methods: ['GET'],
}));

// Rate limiting — prevent brute-force / DoS
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Remove the X-Powered-By header (also handled by helmet, but explicit is clear)
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Users data (would come from a database in production)
const users = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob', email: 'bob@example.com' },
];

app.get('/users', (req, res) => {
  // Validate optional query parameter 'id'
  const { id } = req.query;

  if (id !== undefined) {
    const parsedId = Number(id);

    if (!Number.isInteger(parsedId) || parsedId <= 0) {
      return res.status(400).json({ error: 'Invalid id parameter. Must be a positive integer.' });
    }

    const user = users.find((u) => u.id === parsedId);
    if (!user) {
      return res.status(404).json({ error: 'User not found.' });
    }

    // Return only non-sensitive fields by default
    return res.json({ id: user.id, name: user.name });
  }

  // Strip sensitive fields (email) from the public listing
  const safeUsers = users.map(({ id, name }) => ({ id, name }));
  res.json(safeUsers);
});

// --- 404 Handler ---
app.use((_req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// --- Global Error Handler ---
// Must have 4 parameters so Express recognizes it as an error handler
app.use((err, _req, res, _next) => {
  // Log the full error internally (replace with a proper logger in production)
  console.error('Unhandled error:', err);

  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error.'
      : err.message,
  });
});

// --- Server Start ---
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

