const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// ---------------------------------------------------------------------------
// Security middleware
// ---------------------------------------------------------------------------

// Set secure HTTP headers (hides X-Powered-By, sets CSP, HSTS, etc.)
app.use(helmet());

// Explicit CORS policy – restrict to known origins in production
app.use(
  cors({
    origin: process.env.CORS_ORIGIN || '*',
    methods: ['GET'],
  })
);

// Rate limiting – prevent brute-force / DoS
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Body parsing with size limits (for future POST/PUT routes)
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Disable Express server fingerprinting (belt-and-suspenders with helmet)
app.disable('x-powered-by');

// ---------------------------------------------------------------------------
// Routes
// ---------------------------------------------------------------------------

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate optional query parameters
    const { id } = req.query;

    if (id !== undefined) {
      const numericId = Number(id);
      if (!Number.isInteger(numericId) || numericId <= 0) {
        return res.status(400).json({ error: 'Invalid id parameter. Must be a positive integer.' });
      }
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    if (id !== undefined) {
      const user = users.find((u) => u.id === Number(id));
      if (!user) {
        return res.status(404).json({ error: 'User not found.' });
      }
      return res.json(user);
    }

    return res.json(users);
  } catch (err) {
    next(err);
  }
});

// ---------------------------------------------------------------------------
// 404 handler – catch unmatched routes
// ---------------------------------------------------------------------------
app.use((_req, res) => {
  res.status(404).json({ error: 'Resource not found.' });
});

// ---------------------------------------------------------------------------
// Global error handler – MUST have 4 params so Express recognises it
// ---------------------------------------------------------------------------
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  console.error('Unhandled error:', err);

  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error:
      process.env.NODE_ENV === 'production'
        ? 'Internal server error.'
        : err.message,
  });
});

// ---------------------------------------------------------------------------
// Start server (only when run directly, not when imported for testing)
// ---------------------------------------------------------------------------
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;

